#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[1001];
        scanf("%s", S);
        int i = 0, j = strlen(S) - 1;
        int count = 0;
        while (i < j) {
            if (S[i] != S[j]) count++;
            i++; j--;
        }
        printf("%d\n", count);
    }
    return 0;
}

