code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int i = 0, j = S.length() - 1;
            int count = 0;
            while (i < j) {
                if (S.charAt(i) != S.charAt(j)) count++;
                i++; j--;
            }
            System.out.println(count);
        }
    }
}

